            $stream = @fopen($url, 'r', false, $ctx);
            if (!$stream) {
                return ['success' => false, 'error' => 'Failed to open SSE stream: ' . (error_get_last()['message'] ?? 'unknown')];
            }

            // Set stream timeout
            stream_set_timeout($stream, $timeout);

            // Prepare SQLite storage
            $db_path = $workspace . '/' . basename($db_name);
            $db_dir = dirname($db_path);
            if (!is_dir($db_dir)) @mkdir($db_dir, 0777, true);

            $pdo = null;
