                    }
                    // No data yet, small sleep to avoid busy-wait
                    usleep(10000); // 10ms
                    continue;
                }

                $line_count++;
                $line = rtrim($line, "\r\n");

                // Empty line = end of an event
                if ($line === '') {
                    if ($current_data !== '') {
                        $event = [
                            'type' => $current_event_type ?: 'message',
                            'id' => $current_event_id,
                            'data' => $current_data,
