                // Parse SSE fields
                if (strpos($line, 'event:') === 0) {
                    $current_event_type = trim(substr($line, 6));
                } elseif (strpos($line, 'data:') === 0) {
                    $data_part = trim(substr($line, 5));
                    if ($current_data === '') {
                        $current_data = $data_part;
                    } else {
                        // Multiple data lines are concatenated with newline
                        $current_data .= "\n" . $data_part;
                    }
                } elseif (strpos($line, 'id:') === 0) {
                    $current_event_id = trim(substr($line, 3));
                } elseif (strpos($line, 'retry:') === 0) {
                    // Reconnection time in ms — we don't use this
                } elseif (strpos($line, ':') === 0) {
                    // Comment lines start with colon — ignore
                }
            }

